document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("sendApologistikoButton");e&&e.addEventListener("click",async()=>{try{const t=document.getElementById("ypokatasthmata")?.value||"",o=document.getElementById("ypokatasthmata_stathera")?.value||"",a=document.getElementById("apo_hmeromhnia")?.value||"",n=document.getElementById("eos_hmeromhnia")?.value||"",r=document.getElementById("_csrf")?.value||"";if(!o||!a||!n)return Swal.fire({icon:"warning",title:"Ελλιπή στοιχεία",text:"Συμπληρώστε παράρτημα και ημερομηνίες.",width:"42rem",customClass:{popup:"swal-wide-text"}});e.disabled=!0;const s=await fetch("/ergazomenoi/programmata/wtoApologistikoYperorion",{method:"POST",headers:{"Content-Type":"application/json","CSRF-Token":r},body:JSON.stringify({ypokatasthmata:t,ypokatasthmata_stathera:o,apo_hmeromhnia:a,eos_hmeromhnia:n})}),i=s.headers.get("content-type")||"",d=await s.text();let l;if(!i.includes("application/json"))throw console.error("❌ Expected JSON but got HTML/text:",d),new Error("Το backend δεν επέστρεψε JSON. Πιθανό λάθος route ή CSRF.");if(l=JSON.parse(d),!s.ok||!l.success)throw new Error(l.message||"Αποτυχία δημιουργίας XML υπερωριών.");Swal.fire({icon:"success",title:"Επιτυχία",html:`\n                    <div style="text-align:left;">\n                        <div>${l.message||"Το XML υπερωριών δημιουργήθηκε επιτυχώς."}</div>\n\n                        <hr>\n\n                        <div style="font-size:0.85rem; word-break:break-word;">\n                            <b>XML:</b><br>\n                            ${l.filename||"-"}\n                        </div>\n\n                        <div style="margin-top:8px; font-size:0.8rem; color:#666; word-break:break-word;">\n                            ${l.s3Key||""}\n                        </div>\n                    </div>\n                `,width:"42rem",customClass:{popup:"swal-wide-text"}})}catch(e){console.error("❌ WTO APOLOGISTIKO YPERORION FRONT ERROR:",e),Swal.fire({icon:"error",title:"Σφάλμα",text:e.message||"Αποτυχία δημιουργίας XML υπερωριών.",width:"42rem",customClass:{popup:"swal-wide-text"}})}finally{e.disabled=!1}})});